INSERT INTO pedagogical_content (id, niveau, dimension, question, objectif, tip, tags_theme, tags_filtre)
VALUES
('1', 1, 'COMPRENDRE', 'Pourquoi y a-t-il plusieurs marées par jour ?', 'Comprendre le mécanisme astronomique des marées (Lune/Soleil).', 'La Terre tourne sur elle-même plus vite que la Lune ne tourne autour d''elle.', ARRAY['caracteristiques_littoral','reperes_spatio_temporels'], ARRAY['marée']),
('2', 1, 'COMPRENDRE', 'Comment connaît-on les heures de marée ?', 'Savoir qu''il existe des outils (annuaires, applications) pour connaître les horaires.', 'Les cycles sont si réguliers qu''on peut les calculer des années à l''avance.', ARRAY['reperes_spatio_temporels'], ARRAY['outils','marée']),
('3', 1, 'COMPRENDRE', 'Pourquoi l''heure de la marée n''est pas la même partout ?', 'Comprendre que la forme des côtes influence la propagation de l''onde de marée.', 'Imaginez l''onde de marée comme une vague géante qui doit contourner des obstacles.', ARRAY['caracteristiques_littoral'], ARRAY['marée','zone rocheuse','chenal']),
('4', 1, 'COMPRENDRE', 'Comment s''appelle la zone qui se couvre et se découvre avec la marée ?', 'Connaître le mot ''estran'' et sa signification.', 'C''est un des milieux les plus riches et extrêmes de la planète.', ARRAY['caracteristiques_littoral'], ARRAY['marée','estran']),
('5', 1, 'COMPRENDRE', 'Pourquoi le moment entre deux marées s''appelle l''étale ?', 'Comprendre qu''il y a un moment de pause où le courant est quasi nul.', 'C''est un bon moment pour certaines activités, mais il ne dure pas longtemps !', ARRAY['reperes_spatio_temporels','interactions_climatiques'], ARRAY['marée','courant']),
('6', 2, 'COMPRENDRE', 'Pourquoi connaît-on à l''avance les horaires de marées ?', 'Comprendre la prédictibilité scientifique des marées.', 'La précision des calculs est telle qu''on peut prévoir un horaire à la minute près.', ARRAY['reperes_spatio_temporels'], ARRAY['outils','marée']),
('7', 2, 'COMPRENDRE', 'Pourquoi il est important de connaître l''amplitude de la marée ?', 'Comprendre l''importance du coefficient pour la sécurité et la pratique.', 'Un gros coefficient signifie plus de courant et un estran qui découvre plus loin.', ARRAY['reperes_spatio_temporels'], ARRAY['marée','coefficient']),
('8', 2, 'COMPRENDRE', 'Pourquoi la marée remonte plus vite à certains moments ?', 'Comprendre la règle des douzièmes et la vitesse variable du flot.', 'La marée est la plus rapide à mi-parcours, pas au début ni à la fin.', ARRAY['reperes_spatio_temporels','interactions_climatiques'], ARRAY['marée','courant']),
('9', 2, 'COMPRENDRE', 'Pourquoi la période de « mi-marée » est un moment particulier ?', 'Comprendre que c''est le moment des courants les plus forts.', 'C''est un moment de vigilance accrue pour tous les navigateurs.', ARRAY['interactions_climatiques'], ARRAY['marée','courant']),
('10', 2, 'COMPRENDRE', 'Pourquoi pour parler du mouvement de la mer qui monte et descend, on parle de flot et de jusant ?', 'Connaître le vocabulaire technique précis des marées.', 'Le flot ''flotte'' (monte), le jusant ''descend'' (jus -> bas).', ARRAY['reperes_spatio_temporels'], ARRAY['marée','vocabulaire']),
('11', 2, 'COMPRENDRE', 'Pourquoi le rythme des marées a des incidences sur le « vivant » et les activités humaines ?', 'Comprendre l''interaction marées-biodiversité-activités.', 'Les pêcheurs, les oiseaux, les algues... tout le monde vit au rythme des marées.', ARRAY['biodiversite_saisonnalite','activites_humaines'], ARRAY['marée','écosystème']),
('12', 3, 'COMPRENDRE', 'Comment les marées de mortes eaux et de vives eaux influent sur le « vivant » et les activités humaines ?', 'Comprendre l''impact des différents cycles de marée.', 'Certaines espèces ne se reproduisent qu''en période de vives-eaux.', ARRAY['biodiversite_saisonnalite','activites_humaines'], ARRAY['marée','coefficient','écosystème']),
('13', 1, 'OBSERVER', 'Comment sait-on que l''eau monte et descend ?', 'Identifier des repères visuels simples (rochers, poteaux) pour voir la marée.', 'Choisissez un point fixe et regardez le niveau de l''eau par rapport à lui à 5 minutes d''intervalle.', ARRAY['lecture_paysage'], ARRAY['marée','repères visuels']),
('14', 1, 'OBSERVER', 'Comment sait-on jusqu''où la mer va monter ?', 'Repérer la laisse de haute mer pour anticiper le niveau d''eau.', 'La ligne de débris (algues, bois...) laissée par la dernière marée haute est le meilleur indice.', ARRAY['lecture_paysage','impact_presence_humaine'], ARRAY['marée','laisse de mer','repères visuels']),
('15', 2, 'OBSERVER', 'Comment savoir où poser mon matériel quand j''arrive sur l''estran ?', 'Adapter sa pratique en observant la marée pour des raisons de sécurité.', 'Regardez toujours la laisse de mer et mettez vos affaires plus haut !', ARRAY['lecture_paysage','cohabitation_vivant'], ARRAY['marée','sécurité']),
('16', 1, 'PROTÉGER', 'Pourquoi respecter les zones de reproduction selon les cycles de marée ?', 'Comprendre que certaines zones de l''estran sont des nurseries.', 'Des milliers d''oeufs ou de bébés animaux peuvent être cachés sous vos pieds.', ARRAY['cohabitation_vivant'], ARRAY['zone sensible','marée']),
('17', 1, 'COMPRENDRE', 'Comment se forme le vent ?', 'Comprendre les bases des différences de pression atmosphérique.', 'Le vent est juste de l''air qui se déplace d''une zone de ''haute pression'' (beaucoup d''air) à une zone de ''basse pression'' (peu d''air).', ARRAY['interactions_climatiques'], ARRAY['vent','météo']),
('18', 1, 'COMPRENDRE', 'Qu''est-ce qu''une brise thermique ?', 'Comprendre le phénomène de vent local lié à l''échauffement de la terre.', 'En journée, la terre chauffe plus vite que la mer. L''air chaud de la terre monte, et l''air frais de la mer prend sa place.', ARRAY['interactions_climatiques'], ARRAY['vent','météo','thermique']),
('19', 2, 'COMPRENDRE', 'Comment le vent influence-t-il les activités nautiques ?', 'Comprendre la relation entre force/direction du vent et la pratique.', 'Un vent de terre peut vous éloigner du bord, un vent de mer peut rendre la rentrée difficile.', ARRAY['interactions_climatiques','activites_humaines'], ARRAY['vent','sécurité']),
('20', 1, 'OBSERVER', 'Comment repère-t-on d''où vient le vent ?', 'Identifier des indices visuels pour déterminer la direction du vent.', 'Regardez les drapeaux, la fumée, les rideaux d''eau sur la mer, ou même mettez votre doigt mouillé en l''air !', ARRAY['lecture_paysage'], ARRAY['vent','repères visuels']),
('21', 2, 'OBSERVER', 'Pourquoi dois-tu toujours te soucier du sens du vent et de sa force ?', 'Intégrer l''observation du vent comme un réflexe de sécurité.', 'Le vent est votre moteur, mais aussi votre principal adversaire potentiel. Ne lui tournez jamais le dos.', ARRAY['reperes_spatio_temporels'], ARRAY['vent','sécurité']),
('22', 3, 'OBSERVER', 'Pourquoi je peux savoir qu''une "brise thermique" va se former ?', 'Anticiper la brise en observant les conditions (ciel clair, peu de vent le matin).', 'Si le soleil tape fort le matin et qu''il n''y a pas de vent, attendez-vous à ce que la brise se lève en début d''après-midi.', ARRAY['reperes_spatio_temporels','interactions_climatiques'], ARRAY['vent','météo','thermique']),
('23', 2, 'PROTÉGER', 'Comment adapter sa pratique nautique selon les conditions de vent ?', 'Savoir réduire sa voilure ou changer de zone pour préserver le matériel et l''environnement.', 'Naviguer en surpuissance augmente le risque de casse et de dérangement de la faune.', ARRAY['cohabitation_vivant'], ARRAY['vent','sécurité','adaptation']),
('24', 1, 'COMPRENDRE', 'Qu''est-ce qui fait bouger l''eau de mer ?', 'Comprendre l''origine des courants (marées, vent, différences de densité).', 'Le courant de marée est souvent le plus puissant près des côtes.', ARRAY['interactions_climatiques'], ARRAY['courant']),
('25', 1, 'COMPRENDRE', 'Quels sont les différents types de courants marins ?', 'Distinguer les courants de marée, de dérive (vent), et généraux.', 'Imaginez des rivières invisibles dans la mer, chacune avec sa propre cause.', ARRAY['interactions_climatiques'], ARRAY['courant','marée','vent']),
('26', 2, 'COMPRENDRE', 'Comment les courants influencent-ils la navigation ?', 'Comprendre l''impact des courants sur la vitesse et la trajectoire.', 'Un courant de 2 nœuds peut doubler votre vitesse ou vous arrêter complètement !', ARRAY['interactions_climatiques'], ARRAY['courant','sécurité']),
('27', 1, 'OBSERVER', 'Comment repère-t-on le sens du courant ?', 'Identifier des indices visuels pour déterminer le sens du courant.', 'Regardez l''eau qui s''écoule autour d''une bouée ou d''un poteau. La ''moustache'' d''écume indique le sens.', ARRAY['lecture_paysage'], ARRAY['courant','repères visuels']),
('28', 2, 'OBSERVER', 'Pourquoi dois-tu vérifier le sens du courant ?', 'Intégrer l''observation du courant pour la sécurité et la performance.', 'Aller contre le courant peut vous épuiser et vous mettre en danger.', ARRAY['reperes_spatio_temporels'], ARRAY['courant','sécurité']),
('29', 2, 'PROTÉGER', 'Comment naviguer de façon responsable face aux courants ?', 'Comprendre que les courants sont des corridors de vie à respecter.', 'Les courants transportent nourriture et larves. Évitez de jeter quoi que ce soit dans ces ''autoroutes'' de la vie marine.', ARRAY['cohabitation_vivant'], ARRAY['courant','zone sensible']),
('30', 1, 'COMPRENDRE', 'Comment se forment les vagues ?', 'Comprendre que les vagues sont principalement créées par le vent.', 'Plus le vent souffle fort, longtemps et sur une grande distance, plus les vagues sont grosses.', ARRAY['interactions_climatiques'], ARRAY['vague','vent']),
('31', 1, 'COMPRENDRE', 'Quelle est la différence entre vagues et houle ?', 'Distinguer la mer du vent (local) de la houle (formée au large).', 'La houle est une onde longue et régulière, la mer du vent est courte et désordonnée.', ARRAY['interactions_climatiques'], ARRAY['vague','houle']),
('32', 2, 'COMPRENDRE', 'Comment se produit le déferlement des vagues ?', 'Comprendre que le déferlement est dû à la rencontre avec les fonds marins.', 'Quand la profondeur de l''eau devient trop faible, la vague ''trébuche'' et déferle.', ARRAY['interactions_climatiques','caracteristiques_littoral'], ARRAY['vague','zone rocheuse']),
('33', 1, 'OBSERVER', 'Comment décrirais-tu l''état de la mer ?', 'Apprendre à qualifier la mer (calme, agitée, clapoteuse...).', 'Utilisez des mots simples pour décrire ce que vous voyez. Y a-t-il de l''écume ? Les vagues sont-elles hautes ?', ARRAY['lecture_paysage'], ARRAY['vague','météo']),
('34', 2, 'OBSERVER', 'Comment est la forme des vagues ?', 'Analyser la forme des vagues pour anticiper leur comportement.', 'Des vagues creuses et rapides sont plus dangereuses que des vagues douces et lentes.', ARRAY['lecture_paysage'], ARRAY['vague']),
('35', 3, 'OBSERVER', 'Pourquoi le déferlement est le moment clé de la vague ?', 'Comprendre que c''est le moment où l''énergie de la vague est libérée.', 'Observer la zone de déferlement est essentiel pour la sécurité en surf ou en kayak.', ARRAY['lecture_paysage'], ARRAY['vague','sécurité']),
('36', 3, 'OBSERVER', 'Pourquoi vagues et houle sont liés ?', 'Comprendre comment la houle se transforme en vagues en arrivant à la côte.', 'Vous pouvez avoir de la houle sans vent local, mais pas l''inverse.', ARRAY['interactions_climatiques'], ARRAY['vague','houle','vent']),
('37', 2, 'PROTÉGER', 'Comment respecter les zones sensibles lors de la pratique du surf ?', 'Éviter de piétiner des zones fragiles et de déranger la faune.', 'Utilisez les accès prévus et ne marchez pas sur les rochers couverts d''algues ou de coquillages.', ARRAY['cohabitation_vivant','impact_presence_humaine'], ARRAY['vague','zone sensible']),
('38', 1, 'COMPRENDRE', 'Pourquoi la météo est-elle différente en mer qu''à terre ?', 'Comprendre l''inertie thermique de l''eau et son influence.', 'La mer est plus lente à se réchauffer et à se refroidir que la terre, ce qui adoucit le climat côtier.', ARRAY['interactions_climatiques'], ARRAY['météo']),
('39', 1, 'COMPRENDRE', 'Comment se forment les nuages ?', 'Comprendre le cycle de l''eau et la condensation.', 'Les nuages sont simplement des gouttelettes d''eau ou des cristaux de glace en suspension.', ARRAY['interactions_climatiques'], ARRAY['météo','nuage']),
('40', 2, 'COMPRENDRE', 'Comment évolue la météo marine ?', 'Comprendre que le temps peut changer très vite en mer.', 'Consultez toujours la météo avant de partir et continuez à observer le ciel.', ARRAY['reperes_spatio_temporels'], ARRAY['météo','sécurité','outils']),
('41', 1, 'OBSERVER', 'Comment décrirais-tu l''état du ciel ?', 'Apprendre à qualifier le ciel (clair, nuageux, menaçant...).', 'Les couleurs du ciel au lever et au coucher du soleil peuvent donner des indices sur le temps à venir.', ARRAY['lecture_paysage'], ARRAY['météo','nuage']),
('42', 2, 'OBSERVER', 'Comment est la forme des nuages ?', 'Reconnaître quelques types de nuages de base et leur signification.', 'Les gros nuages sombres (cumulonimbus) annoncent souvent des orages.', ARRAY['lecture_paysage'], ARRAY['météo','nuage','repères visuels']),
('43', 2, 'PROTÉGER', 'Comment anticiper pour la sécurité et la préservation ?', 'Comprendre qu''anticiper la météo permet de ne pas se mettre en danger ni de déranger la faune.', 'Un orage peut être dangereux pour vous et stressant pour les animaux.', ARRAY['cohabitation_vivant'], ARRAY['météo','sécurité','adaptation']),
('44', 1, 'COMPRENDRE', 'Comment se forment les dunes ?', 'Comprendre le rôle du vent et des plantes dans la formation des dunes.', 'C''est le sable transporté par le vent qui est piégé par les plantes pionnières.', ARRAY['caracteristiques_littoral'], ARRAY['dune','vent']),
('45', 2, 'COMPRENDRE', 'Pourquoi, le massif dunaire est composé de plusieurs strates ?', 'Comprendre l''étagement de la végétation dunaire.', 'De la plage vers l''intérieur : plantes pionnières, dune mobile, dune grise, forêt.', ARRAY['caracteristiques_littoral','biodiversite_saisonnalite'], ARRAY['dune','écosystème']),
('46', 1, 'OBSERVER', 'Comment décrirais-tu l''état de la plage ?', 'Apprendre à observer les différents éléments de la plage (sable, galets, dunes).', 'Regardez la couleur du sable, la taille des galets, la hauteur des dunes.', ARRAY['lecture_paysage'], ARRAY['dune']),
('47', 2, 'OBSERVER', 'Pourquoi la dune bouge d''une marée à l''autre ?', 'Observer les signes d''érosion et d''accumulation de sable.', 'Après une tempête, vous pouvez voir des ''falaises'' de sable là où la dune a été attaquée par la mer.', ARRAY['lecture_paysage'], ARRAY['dune','marée','érosion']),
('48', 1, 'PROTÉGER', 'Pourquoi les dunes sont fragiles ?', 'Comprendre que le piétinement détruit la végétation qui retient le sable.', 'Utilisez toujours les chemins balisés pour traverser les dunes.', ARRAY['impact_presence_humaine','cohabitation_vivant'], ARRAY['dune','zone sensible','érosion']),
('49', 3, 'PROTÉGER', 'Pourquoi on parle de plus en plus du recul du trait de côte ?', 'Comprendre l''enjeu de l''érosion côtière et du changement climatique.', 'La montée du niveau de la mer et les tempêtes plus fortes accélèrent ce phénomène naturel.', ARRAY['impact_presence_humaine'], ARRAY['dune','érosion']),
('50', 1, 'COMPRENDRE', 'Comment s''appelle la bande colorée sur le sable, quand la mer se retire ?', 'Connaître le terme ''laisse de mer''.', 'C''est un peu la ''poubelle naturelle'' de la mer, mais une poubelle très utile !', ARRAY['caracteristiques_littoral'], ARRAY['laisse de mer','vocabulaire']),
('51', 1, 'COMPRENDRE', 'D''où viennent les débris de la laisse de mer ?', 'Distinguer les débris naturels (algues, bois) des déchets humains.', 'Les éléments naturels sont essentiels à l''écosystème, pas les déchets !', ARRAY['impact_presence_humaine'], ARRAY['laisse de mer','pollution']),
('52', 2, 'COMPRENDRE', 'Comment les courants et marées transportent-ils les débris ?', 'Comprendre que la laisse de mer est un indicateur des mouvements de l''eau.', 'La forme de la laisse de mer peut vous donner des indices sur la direction des courants.', ARRAY['interactions_climatiques'], ARRAY['laisse de mer','courant','marée']),
('53', 1, 'OBSERVER', 'Que peut-on trouver dans la laisse de mer ?', 'Identifier les différents composants de la laisse de mer.', 'Cherchez des coquillages, des ''œufs de raie'', des os de seiche, des algues...', ARRAY['biodiversite_saisonnalite'], ARRAY['laisse de mer']),
('54', 2, 'OBSERVER', 'Comment la laisse de mer peut-elle être un indicateur environnemental ?', 'Comprendre que la composition de la laisse renseigne sur la santé de l''écosystème.', 'Trop de plastique est un mauvais signe. La présence de certaines espèces peut être un bon signe.', ARRAY['impact_presence_humaine','biodiversite_saisonnalite'], ARRAY['laisse de mer','pollution','écosystème']),
('55', 2, 'PROTÉGER', 'Comment pratiquer un nettoyage raisonné de la plage ?', 'Savoir ramasser les déchets humains sans enlever les éléments naturels.', 'Ne ramassez que ce qui est d''origine humaine. Laissez le bois et les algues, ils nourrissent la dune.', ARRAY['impact_presence_humaine'], ARRAY['laisse de mer','pollution']),
('56', 3, 'PROTÉGER', 'Comment réduire les déchets à la source pour limiter la pollution marine ?', 'Comprendre que la meilleure solution est de ne pas produire de déchets.', 'Utilisez des gourdes, évitez les emballages uniques, ne laissez rien derrière vous.', ARRAY['impact_presence_humaine'], ARRAY['pollution']),
('57', 1, 'COMPRENDRE', 'Pourquoi y a-t-il beaucoup de vie humaine, animale et végétale sur l''espace littoral ?', 'Comprendre que le littoral est un écotone riche et productif.', 'C''est une zone de rencontre entre la terre et la mer, ce qui multiplie les habitats et les ressources.', ARRAY['biodiversite_saisonnalite','caracteristiques_littoral'], ARRAY['écosystème']),
('58', 1, 'COMPRENDRE', 'Comment les espèces marines sont-elles adaptées à leur environnement ?', 'Comprendre les adaptations spécifiques (respiration, camouflage...).', 'Le crabe a une carapace, le poisson a des branchies, l''algue est flexible pour résister aux vagues.', ARRAY['biodiversite_saisonnalite'], ARRAY['adaptation']),
('59', 2, 'COMPRENDRE', 'Comment fonctionnent les chaînes alimentaires marines ?', 'Comprendre les relations prédateurs-proies en mer.', 'Du plancton aux grands prédateeurs, chaque maillon est essentiel.', ARRAY['biodiversite_saisonnalite'], ARRAY['écosystème']),
('60', 2, 'COMPRENDRE', 'Quels sont les cycles biologiques des espèces marines ?', 'Comprendre les cycles de vie (reproduction, migration).', 'Les oiseaux migrateurs s''arrêtent sur nos côtes pour se reposer et se nourrir.', ARRAY['biodiversite_saisonnalite'], ARRAY['migration','reproduction']),
('61', 1, 'OBSERVER', 'Comment peut-on repérer des traces de présence animale sur ce site ?', 'Identifier des indices de faune (empreintes, plumes, coquilles).', 'Les traces de pas sur le sable humide sont un excellent indice.', ARRAY['lecture_paysage'], ARRAY['repères visuels','faune']),
('62', 2, 'OBSERVER', 'Comment observer le vivant sans déranger', '"Retenir qu’il y a dérangement dès qu’il y a un changement de comportement', 'Rester à distance, ne pas faire de bruit, utiliser des jumelles', ARRAY['cohabitation_vivant'], ARRAY['faune','zone sensible']),
('63', 1, 'PROTÉGER', 'Pourquoi je peux observer tout en étant discret ?', 'Comprendre que la discrétion évite le stress et la fuite des animaux.', 'Un animal qui fuit utilise une énergie précieuse dont il a besoin pour survivre.', ARRAY['cohabitation_vivant'], ARRAY['faune','zone sensible']),
('64', 1, 'PROTÉGER', 'Pourquoi un dérangement peut causer du tort au « vivant » ?', 'Comprendre les conséquences du dérangement (abandon du nid, stress...).', 'Si des parents sont dérangés, ils peuvent abandonner leurs œufs ou leurs petits.', ARRAY['cohabitation_vivant'], ARRAY['faune','zone sensible']),
('65', 2, 'PROTÉGER', 'Comprendre qu’au fil des saisons le vivant est différent et choisit le site en fonction de ses besoins (hivernage, reproduction….)', 'Comprendre la multifonctionnalité des habitats et l''importance de les préserver.', 'Il y a des moments clés à chaque saison pour chaque espèce, il est important de les repérer pour savoir qui est là, à quel moment et pourquoi', ARRAY['cohabitation_vivant','biodiversite_saisonnalite'], ARRAY['écosystème','zone sensible']),
('66', 2, 'PROTÉGER', 'Pourquoi la présence humaine doit limiter son impact sur un lieu de vie qui n''est pas le sien mais celui de nombreuses espèces ?', 'Comprendre notre responsabilité en tant qu''invités dans un milieu naturel.', 'Nous ne sommes que de passage, laissons l''endroit comme nous l''avons trouvé.', ARRAY['impact_presence_humaine','cohabitation_vivant'], ARRAY['zone sensible']),
('67', 3, 'PROTÉGER', 'Pourquoi chacun peut œuvrer en faveur de la biodiversité ?', 'Comprendre que chaque geste compte, de la protection locale à l''action globale.', 'Signaler une espèce, ramasser un déchet, respecter les zones... tout aide.', ARRAY['cohabitation_vivant','sciences_participatives'], ARRAY['action citoyenne']),
('68', 1, 'COMPRENDRE', 'Comment prendre en compte les rythmes naturels', 'Comprendre que les activités humaines sont soumises à différents rythmes : le rythme quotidien des marées, le rythme mensuel des cycles de la lune, le rythme annuel des saisons …', 'La nature aura toujours le dernier mot, à charge pour l’homme d’ajuster ses activités pour être en sécurité et en harmonie avec le lieu. L’adaptation à tous ces rythmes passe par la connaissance.', ARRAY['reperes_spatio_temporels'], ARRAY['adaptation']),
('69', 2, 'COMPRENDRE', 'Quelles sont les interdépendances en milieu marin ?', 'Comprendre que tous les éléments (vent, courant, faune, flore) sont liés.', 'Le vent crée les vagues, qui façonnent la côte, qui abrite des espèces spécifiques...', ARRAY['interactions_climatiques','biodiversite_saisonnalite'], ARRAY['écosystème']),
('70', 1, 'OBSERVER', 'Comment lire son environnement pour naviguer en sécurité ?', 'Apprendre à observer les éléments clés pour une pratique sécuritaire.', 'Avant de partir, prenez 5 minutes pour regarder le ciel, la mer, le vent.', ARRAY['lecture_paysage'], ARRAY['sécurité','observation']),
('71', 2, 'OBSERVER', 'Comment repères-tu ta zone de navigation, quels amers prends-tu ?', 'Apprendre à utiliser des points de repère fixes pour se situer.', 'Un amer est un point de repère remarquable sur la côte (clocher, phare, château d''eau).', ARRAY['lecture_paysage'], ARRAY['repères visuels','sécurité']),
('72', 2, 'OBSERVER', 'Pourquoi tout ce qui est inhabituel (en mer, comme à terre) doit être signalé ?', 'Devenir une sentinelle de l''environnement.', 'Une pollution, une espèce échouée, un filet abandonné... votre signalement peut déclencher une action.', ARRAY['sciences_participatives'], ARRAY['action citoyenne']),
('73', 1, 'PROTÉGER', 'Comment avoir un impact minimal sur l''environnement ?', 'Apprendre les gestes de base pour limiter son empreinte écologique.', 'Ne rien laisser derrière soi est la règle d''or.', ARRAY['impact_presence_humaine'], ARRAY['éco-geste']),
('74', 2, 'PROTÉGER', 'Comment partager l''espace avec la faune et la flore ?', 'Adopter des comportements respectueux pour minimiser le dérangement.', 'Considérez que vous êtes dans leur maison, pas l''inverse.', ARRAY['cohabitation_vivant'], ARRAY['zone sensible','faune','flore']),
('75', 1, 'COMPRENDRE', 'Quelles sont les activités humaines en mer et sur le littoral ?', 'Identifier les différents usages du littoral (pêche, loisirs, transport...).', 'Regardez autour de vous : pêcheurs, plaisanciers, promeneurs... nous partageons tous cet espace.', ARRAY['activites_humaines'], ARRAY[]),
('76', 2, 'COMPRENDRE', 'Quels impacts ont les activités humaines sur le milieu marin ?', 'Comprendre les conséquences de nos actions (pollution, surexploitation...).', 'Même un petit déchet peut avoir un impact énorme sur un animal.', ARRAY['impact_presence_humaine'], ARRAY['pollution']),
('77', 2, 'COMPRENDRE', 'Qu''est-ce que l''économie bleue ?', 'Comprendre le concept d''économie maritime durable.', 'C''est l''idée de développer des activités économiques qui respectent la santé de l''océan.', ARRAY['activites_humaines'], ARRAY['économie']),
('78', 2, 'OBSERVER', 'Comment les pratiques évoluent-elles vers plus de durabilité ?', 'Observer les innovations et les changements de comportement.', 'Matériaux recyclés, moteurs électriques, zones protégées... les choses bougent !', ARRAY['activites_humaines'], ARRAY['adaptation','innovation']),
('79', 3, 'PROTÉGER', 'Comment adopter des modes de consommation durables et écologiques ?', 'Comprendre que nos choix en tant que consommateurs ont un impact.', 'Choisir des produits de la mer issus de la pêche durable, réduire sa consommation de plastique.', ARRAY['impact_presence_humaine'], ARRAY['éco-geste']),
('80', 3, 'PROTÉGER', 'Comment aider à la préservation du site en participant à des programmes de recherche via des sites de sciences participatives ?', 'Savoir utiliser les outils de sciences participatives.', 'Des applications comme iNaturalist ou OBSenMER permettent de signaler vos observations.', ARRAY['sciences_participatives'], ARRAY['action citoyenne','outils']),
('81', 2, 'PROTÉGER', 'Pourquoi chacun peut devenir acteur de la préservation de la nature tout en améliorant la connaissance en général ?', 'Comprendre la valeur de chaque observation individuelle.', 'Des milliers d''yeux valent mieux qu''un seul. Vos données sont précieuses pour les scientifiques.', ARRAY['sciences_participatives','cohabitation_vivant'], ARRAY['action citoyenne']),
('82', 1, 'COMPRENDRE', 'Qu’est-ce qu’un nuage ?', 'Décrire la nature fondamentale d''un nuage.', 'Un nuage est une collection visible de minuscules gouttelettes d’eau ou de cristaux de glace suspendus dans l’air.', ARRAY['Nuages'], ARRAY[]),
('83', 1, 'COMPRENDRE', 'Pourquoi les nuages peuvent-ils être blancs ou gris foncés ?', 'Expliquer la variation de couleur des nuages.', 'Parce que les nuages épais ou chargés de gouttelettes cristallisées laissent passer moins de lumière ; un nuage très épais peut paraître gris ou sombre', ARRAY['Nuages'], ARRAY[]),
('84', 1, 'COMPRENDRE', 'Quel rôle joue un nuage dans le cycle de l’eau ?', 'Identifier le rôle des nuages dans le cycle de l''eau.', 'Les nuages sont une étape du cycle de l’eau : l’eau s’évapore, monte, forme un nuage, puis retombe sous forme de précipitations (pluie, neige).', ARRAY['Nuages','Cycle de l''eau'], ARRAY[]),
('85', 1, 'COMPRENDRE', 'Qu’est-ce que le vent ?', 'Définir ce qu''est le vent.', 'Le vent est le déplacement de l’air par rapport à la surface de la Terre, causé par des différences de pression atmosphérique', ARRAY['Vent'], ARRAY[]),
('86', 1, 'COMPRENDRE', 'Qu’entend-on par « oiseau migrateur » en Normandie ?', 'Définir la notion d''oiseau migrateur en Normandie.', 'Un oiseau migrateur est une espèce qui effectue chaque année un déplacement régulier (souvent vers le sud ou vers le nord) pour l’hiver ou la reproduction, et qui passe ou s’arrête en Normandie dans ses trajets', ARRAY['Oiseaux migrateurs','Migrations'], ARRAY[]),
('87', 1, 'COMPRENDRE', 'Pourquoi la Normandie est-elle un territoire important pour les migrations d’oiseaux ?', 'Expliquer l''importance de la Normandie pour les migrations aviaires.', 'Parce que le littoral, les zones humides et les estuaires normands constituent des escales ou des zones d’hivernage pour de nombreuses espèces migratrices', ARRAY['Oiseaux migrateurs','Migrations','Biodiversité'], ARRAY[]),
('88', 2, 'OBSERVER', 'Combien d’espèces de mammifères marins ont été observées sur les côtes normandes, et quelles sont les espèces les plus fréquemment observées ?', 'Connaître les mammifères marins observés en Normandie.', 'On recense **24 espèces de mammifères marins** observées ou échouées sur le littoral normand. Parmi les plus fréquentes : le Phoque veau-marin, le Phoque gris et le Marsouin commun.', ARRAY['Mammifères marins','Biodiversité','caracteristiques_littoral','lecture_paysage'], ARRAY[]),
('89', 1, 'COMPRENDRE', 'Qu’est-ce qu’un courant marin ?', 'Définir ce qu''est un courant marin.', 'C’est un mouvement dirigé d’eau de mer, souvent horizontal, qui circule dans l’océan ou près des côtes. Pense-y comme à une « rivière dans l’océan ».', ARRAY['Courants marins'], ARRAY[]),
('90', 1, 'COMPRENDRE', 'Qu’est-ce qu’une houle ?', 'Expliquer la nature de la houle.', 'Une houle est une série d’ondes de gravité à la surface de l’eau qui ont été générées par du vent à distance et qui ont voyagé loin de leur origine, devenant organisées et régulières. Contrairement aux vagues « locales » générées directement par le vent à proximité, une houle vient souvent d’un système de tempête éloigné', ARRAY['Houle','Vagues'], ARRAY[]),
('91', 1, 'COMPRENDRE', 'Pourquoi les horaires de marée changent-ils chaque jour à un même endroit ?', 'Comprendre le décalage quotidien des marées.', 'Parce que le jour lunaire (environ 24 h 50 min) est plus long que le jour solaire (24 h), donc chaque jour on revient « un peu plus tard » sous l’effet principal de la Lune Le décalage quotidien des horaires de marée est dû essentiellement au fait que la Lune **avance** dans son orbite pendant que la Terre tourne. Quelques éléments clés : Une « journée lunaire » (le temps que met un point de la Terre pour revenir sous la Lune) est d’environ **24 h 50 min** (et non de 24 h) parce que la Lune se déplace dans son orbite pendant que la Terre tourne. Puisque la Terre doit tourner un peu plus pour « rattraper » la position de la Lune, chaque marée haute, ou marée basse, se produit environ **50 minutes plus tard** que la veille (dans les zones à marée semi-diurne typiques).', ARRAY['Marées'], ARRAY[]),
('92', 1, 'OBSERVER', 'Qu’est-ce que la curiosité a-t-elle à voir avec l’observation de la nature ?', 'Expliquer le rôle de la curiosité dans l''observation.', 'Un bon observateur est animé par la curiosité : il se questionne, il se demande « quoi ? », « pourquoi ? », « comment ? ».', ARRAY['Observation','Nature'], ARRAY[]),
('93', 1, 'OBSERVER', 'Comment l’usage des sens (vue, ouïe, toucher…) contribue-t-il à être un bon observateur de la nature ?', 'Identifier l''importance des sens en observation.', 'Utiliser activement les sens permet de détecter des détails subtils : l’observation ne se limite pas à regarder, mais aussi à écouter, sentir, toucher (quand c’est possible et respectueux)', ARRAY['Observation','Sens'], ARRAY[]),
('94', 1, 'OBSERVER', 'Quel rôle joue la connaissance des espèces et des milieux dans l’observation de la nature ?', 'Mettre en évidence le lien entre connaissance et observation.', 'Connaître (ou chercher à connaître) les plantes, animaux, habitats de sa région permet de reconnaître ce qui est «normal», ce qui est «nouveau» ou «significatif». Cela enrichit l’observation', ARRAY['Observation','Connaissance','Biodiversité'], ARRAY[]),
('95', 1, 'OBSERVER', 'Pourquoi le respect de la nature est-il une composante d’un bon observateur ?', 'Comprendre l''éthique de l''observation naturelle.', 'Parce que l’observation ne doit pas nuire à ce qu’on observe : respecter animaux, plantes, milieux, ne pas les déranger ou les endommager. Cela garantit que l’observation est éthique et durable', ARRAY['Observation','Respect','Éthique'], ARRAY[]),
('96', 1, 'OBSERVER', 'Qu’est-ce que l’on entend par « état de la mer » ?', 'Définir la notion d''état de la mer.', 'C’est l’ensemble des conditions de surface de la mer à un lieu donné, typiquement décrites par la hauteur des vagues, la longueur d’onde, la direction du vent ou de la houle, et parfois la fréquence des creux. Bien connaître l’état de la mer permet d’évaluer la sécurité et la difficulté de l’activité', ARRAY['État de la mer','Navigation'], ARRAY[]),
('97', 1, 'OBSERVER', 'Quels éléments visuels/observables pouvez-vous vérifier en bord de mer pour estimer l’état de la mer ?', 'Identifier les signes visuels de l''état de la mer.', 'La présence de « moutons » (crêtes de vagues blanches) → vent important ; La direction des vagues / houle et si elles cassent ou non ; La visibilité à l’horizon (brume, pluie, mer agitée) → reflet des conditions météo. Ces observations simples peuvent donner beaucoup d’indices avant même d’être dans l’eau.', ARRAY['État de la mer','Observation','Sécurité'], ARRAY[]),
('98', 1, 'PROTÉGER', 'Pourquoi la protection de l’environnement est-elle importante pour la santé humaine ?', 'Comprendre le lien entre protection environnementale et santé.', 'Parce que la pollution de l’air, de l’eau ou des sols peut entraîner des maladies respiratoires, des cancers, des infections hydriques, etc. On peut voir l’environnement comme notre « maison commune » : si elle est en mauvais état, notre santé en pâtit.', ARRAY['Protection environnement','Santé','Pollution'], ARRAY[]),
('99', 2, 'COMPRENDRE', 'Comment se forme un nuage ?', 'Expliquer le processus de formation des nuages.', 'L’air chaud et humide monte, se refroidit, la vapeur d’eau se condense autour de particules en suspension (poussière, sel…) et forme des gouttelettes ou des cristaux, ce qui crée un nuage.', ARRAY['Nuages','Formation'], ARRAY[]),
('100', 2, 'COMPRENDRE', 'Pourquoi l’air qui monte dans l’atmosphère favorise-t-il la formation de nuages ?', 'Détailler le rôle de l''air ascendant dans la nébulosité.', 'Parce que lorsqu’il monte, l’air se refroidit, ne peut plus contenir autant de vapeur d’eau, et la vapeur se condense pour former des gouttelettes ou des cristaux => nuage.', ARRAY['Nuages','Atmosphère'], ARRAY[]),
('101', 2, 'COMPRENDRE', 'Pourquoi les nuages sont-ils souvent utilisés comme indicateurs de changement météo ?', 'Identifier l''utilité des nuages comme indicateurs météorologiques.', 'Parce que certains types de nuages se forment dans des conditions spécifiques : par exemple, un voile de cirrostratus peut annoncer un front chaud, des cumulus verticaux une instabilité, un ciel entièrement stratus un temps stable mais couvert. Le type + altitude + forme peuvent donc être des signaux', ARRAY['Nuages','Météo','Prévisions'], ARRAY[]),
('102', 2, 'COMPRENDRE', 'Qu’est-ce qu’un vent local tel que la brise de mer et de terre, et comment se forme-t-il ?', 'Expliquer la formation des vents locaux (brises).', 'Un vent local comme la brise de mer se forme parce que la terre se réchauffe plus vite que l’eau : l’air au-dessus de la terre monte, créant une basse pression, et l’air plus frais venant de la mer se déplace vers la terre. La nuit, la situation s’inverse avec la brise de terre vers la mer.', ARRAY['Vent','Brise','Météo locale'], ARRAY[]),
('103', 2, 'COMPRENDRE', 'Pourquoi est-il important de tenir compte des migrations pour la gestion des zones naturelles en Normandie ?', 'Comprendre l''impact des migrations sur la gestion des zones naturelles.', 'Parce que les zones d’escale ou d’hivernage doivent être protégées (zones humides, littoraux), car la perturbation ou destruction de ces milieux peut compromettre le succès migratoire des espèces', ARRAY['Migrations','Biodiversité','Gestion zones naturelles'], ARRAY[]),
('104', 2, 'COMPRENDRE', 'Quels sont les trois principaux facteurs qui déterminent la taille d’une houle (ou vague générée) ?', 'Identifier les facteurs influençant la taille de la houle.', 'La vitesse du vent, la durée pendant laquelle il souffle, et la distance non interrompue sur laquelle il souffle (fetch) : c’est-à-dire la surface d’eau sur laquelle le vent agit sans interruption', ARRAY['Houle','Vagues','Facteurs'], ARRAY[]),
('105', 2, 'OBSERVER', 'Pourquoi est-il utile de vérifier la direction du vent et celle de la houle ?', 'Comprendre l''importance de la direction du vent et de la houle pour la sécurité.', 'Parce que le vent peut générer des vagues ou accentuer la houle. Si le vent souffle contre la direction de la houle, la mer se « dérange », avec des vagues plus courtes, hachées et donc dangereuses.', ARRAY['Vent','Houle','Sécurité nautique'], ARRAY[]),
('106', 2, 'OBSERVER', 'Que faut-il observer concernant la marée ou le courant avant une activité nautique ?', 'Identifier les points d''observation essentiels pour la marée et les courants.', 'Vérifier l’heure de haute/basse mer, l’amplitude, et identifier les zones de courant fort ou « ressac » potentiels', ARRAY['Marées','Courants','Sécurité nautique'], ARRAY[]),
('107', 2, 'OBSERVER', 'Pourquoi l’observation de l’état de la mer est-elle incontournable pour la sécurité nautique ?', 'Expliquer le rôle de l''observation marine pour la sécurité.', 'Parce qu’elle permet d’évaluer le niveau de risque (vagues, houle, courant, vent), d’adapter le matériel, de choisir un bon itinéraire ou de reporter si nécessaire. L’ignorance peut conduire à des situations dangereuses', ARRAY['État de la mer','Sécurité nautique'], ARRAY[]),
('108', 2, 'OBSERVER', 'Qu’est-ce que la « période » d’une houle ?', 'Définir la période d''une houle.', 'La période est le temps (exprimé en secondes) entre le passage de deux crêtes consécutives d’onde à un même point fixe. Les houles ont typiquement des périodes plus longues que les vagues de vent', ARRAY['Houle','Vagues','Terminologie'], ARRAY[]),
('109', 2, 'PROTÉGER', 'Quelle est la relation entre protection de l’environnement et « ressources naturelles » ?', 'Comprendre le lien entre protection et gestion des ressources naturelles.', 'La protection de l’environnement implique de gérer durablement les ressources naturelles (eau, forêts, sols, biodiversité) afin qu’elles puissent satisfaire les besoins actuels **et futurs** sans s’épuiser', ARRAY['Protection environnement','Ressources naturelles','Développement durable'], ARRAY[]),
('110', 2, 'PROTÉGER', 'Pourquoi la gestion des déchets plastiques est-elle un enjeu majeur ?', 'Expliquer l''importance de la gestion des déchets plastiques.', 'Parce que les plastiques non recyclés polluent l’eau, les sols, et les écosystèmes, en particulier marins', ARRAY['Déchets plastiques','Pollution marine','Environnement'], ARRAY[]),
('111', 2, 'PROTÉGER', 'Pourquoi le littoral normand est-il considéré comme « un territoire à forts enjeux de biodiversité » ?', 'Identifier les raisons de la richesse de la biodiversité du littoral normand.', 'Parce qu’il combine **entre mer, littoral, plaine et bocage** un ensemble de milieux diversifiés qui se trouvent dans un état d’équilibre fragile entre usages humains et nature', ARRAY['Biodiversité','Littoral normand','Enjeux environnementaux'], ARRAY[]),
('112', 2, 'PROTÉGER', 'Quel réseau de protection existe en Normandie pour les milieux naturels incluant des parties marines ?', 'Connaître les dispositifs de protection marine en Normandie.', 'Le réseau **Natura 2000** compte en Normandie 94 sites dont **34 sites avec une partie marine**. Ces zones contribuent à protéger des habitats et des espèces marines ou littorales.', ARRAY['Protection marine','Natura 2000','Normandie'], ARRAY[]),
('113', 4, 'COMPRENDRE', 'Comment la topographie côtière ou la configuration locale peuvent-elles affecter l’état de la mer ?', 'Expliquer l''influence de la géographie côtière sur l''état de la mer.', 'Une baie fermée ou un cap exposé modifient la façon dont la houle entre, les courants, et la vitesse du vent. Une pente douce ou un récif proche peuvent amplifier les vagues', ARRAY['État de la mer','Topographie côtière','Phénomènes physiques'], ARRAY[]),
('114', 4, 'COMPRENDRE', 'Quels sont les trois critères principaux pour classer les nuages ?', 'Détailler les critères de classification des nuages.', 'Le **niveau d’altitude** (bas, moyen, haut), la **forme** (cumulo- : en amas, strato- : en couches, cirro- : élevé/filamenteux) et la **capacité de précipitation** (par exemple les « nimbus »). Connaître ces critères permet d’identifier rapidement un type de nuage', ARRAY['Nuages','Classification'], ARRAY[]),
('115', 4, 'COMPRENDRE', 'Quel type de nuage indique souvent des orages ou des conditions instables ?', 'Identifier le nuage annonciateur d''orages.', 'Le nuage Cumulonimbus : développement vertical important, capable de produire pluie intense, grêle, tonnerre.', ARRAY['Nuages','Orages','Météo'], ARRAY[]),
('116', 4, 'COMPRENDRE', 'Qu’est-ce que « la phénologie de la migration » et comment celle-ci évolue en Normandie ?', 'Définir la phénologie de la migration et son évolution en Normandie.', 'La phénologie de la migration désigne le moment (date) auquel les oiseaux migrateurs commencent ou terminent leur migration. En Normandie, par exemple, certaines hirondelles et martinets arrivent ~18 jours plus tôt qu’il y a 50 ans', ARRAY['Migrations','Oiseaux migrateurs','Phénologie'], ARRAY[]),
('117', 4, 'COMPRENDRE', 'Comment le changement climatique peut-il influencer les migrations d’oiseaux en Normandie ?', 'Expliquer l''impact du changement climatique sur les migrations.', 'Il peut modifier les dates de départ ou d’arrivée (phénologie), la répartition des espèces, ou la durée d’hivernage. Exemple : les hirondelles arrivent plus tôt.', ARRAY['Changement climatique','Migrations','Oiseaux migrateurs'], ARRAY[]),
('118', 4, 'COMPRENDRE', 'Quel est le rôle des courants marins dans la distribution des nutriments dans l’océan ?', 'Comprendre l''importance des courants marins pour les nutriments.', 'Les courants transportent de l’eau riche en nutriments depuis les profondeurs ou les zones fertiles vers la surface ou vers d’autres régions, permettant à la chaîne alimentaire de prospérer', ARRAY['Courants marins','Nutriments','Océanographie'], ARRAY[]),
('119', 4, 'COMPRENDRE', 'Quels sont les trois grands facteurs qui entraînent les courants de surface ?', 'Identifier les facteurs moteurs des courants de surface.', 'Le vent, la rotation de la Terre (effet de Coriolis) et la forme des côtes / fonds marins', ARRAY['Courants marins','Facteurs','Océanographie'], ARRAY[]),
('120', 1, 'OBSERVER', 'Avant de s’engager sur l’eau quel comportement d’observation est recommandé ?', 'Décrire le protocole d''observation pré-activité nautique.', 'Prendre quelques minutes pour observer : la mer depuis le rivage, noter la fréquence des vagues grandes (sets), voir où elles cassent, identifier zones plus calmes (canaux), et vérifier que les conditions correspondent à ce que vous pouvez gérer', ARRAY['Observation','Sécurité nautique','Préparation','lecture_paysage','reperes_spatio_temporels'], ARRAY['outils','courant','coefficient','vocabulaire','marée']),
('121', 4, 'OBSERVER', 'Quelle alerte visuelle peut indiquer une montée rapide du vent ou un changement de conditions maritimes ?', 'Identifier les signes visuels d''un changement rapide des conditions maritimes.', 'Par exemple : drapeaux qui se dressent, mousse étendue à la surface, nuages d’orage qui arrivent, diminution soudaine de visibilité. Ces signes indiquent de renforcer la vigilance ou de différer la sortie', ARRAY['Alertes météo','Sécurité nautique','Observation'], ARRAY[]),
('122', 4, 'OBSERVER', 'Quelle différence principale existe entre une houle et une vague de vent  ?', 'Distinguer houle et vague de vent.', 'Une vague de vent est générée localement par le vent soufflant à proximité / dans la même zone, alors qu’une houle a voyagé hors de la zone de génération, le vent local ne la contrôle plus directement. **Commentaire** : On peut souvent reconnaître une houle à ses longues périodes d’onde et sa régularité.', ARRAY['Houle','Vagues','Différences'], ARRAY[]),
('123', 4, 'OBSERVER', 'Quel rôle joue l’orientation (direction) de la houle pour une plage ou un spot côtier ?', 'Comprendre l''influence de l''orientation de la houle.', 'L’angle d’arrivée de la houle par rapport à la côte influence comment les vagues vont « prendre » la côte : une houle bien orientée face au littoral aura plus de potentiel pour produire de bonnes vagues, tandis qu’une houle venant de travers peut être moins efficace ou dégradée', ARRAY['Houle','Vagues','Orientation'], ARRAY[]),
('124', 4, 'OBSERVER', 'Pourquoi est-il utile de connaître les conditions de houle avant une activité nautique ou littorale ?', 'Expliquer l''importance de connaître les conditions de houle.', 'Parce que la houle influence la hauteur des vagues, la période, l’énergie transmise, le moment d’arrivée des séries de vagues, et donc la sécurité (ex : pour baignade, surf, navigation) et l’érosion côtière. Même par vent calme, une grande houle lointaine peut provoquer des vagues puissantes ou des surcôtes', ARRAY['Houle','Sécurité nautique','Érosion côtière'], ARRAY[]),
('125', 4, 'PROTÉGER', 'Quel est le lien entre consommation responsable et sensibilisation à l’environnement ?', 'Établir le lien entre consommation responsable et sensibilisation environnementale.', 'Une personne sensibilisée fait des choix plus responsables (produits durables, moins de déchets, consommation raisonnée) ce qui réduit l’impact environnemental', ARRAY['Consommation responsable','Sensibilisation','Environnement'], ARRAY[]),
('126', 4, 'PROTÉGER', 'Quelle est la différence entre sensibilisation et action environnementale ?', 'Distinguer sensibilisation et action environnementale.', 'La sensibilisation concerne la prise de conscience et l’information ; l’action est l’application concrète (changer des habitudes, participer à des initiatives).', ARRAY['Sensibilisation','Action environnementale'], ARRAY[]),
('127', 4, 'PROTÉGER', 'Pourquoi dit-on parfois qu’« il n’est pas trop tard » pour agir en matière de climat et environnement ?', 'Expliquer l''espoir d''action face aux défis climatiques.', 'Parce que même si certains effets du changement sont déjà irréversibles, la réduction des émissions, l’adaptation et les transitions vers des modes de vie plus durables peuvent limiter les risques futurs et améliorer la résilience des sociétés', ARRAY['Changement climatique','Action environnementale','Résilience'], ARRAY[]),
('128', 4, 'PROTÉGER', 'Pourquoi la présence de mammifères marins en Normandie est-elle un sujet de suivi et de préoccupation ?', 'Comprendre l''importance du suivi des mammifères marins comme indicateurs écologiques.', 'Parce que ces espèces sont souvent situées au sommet de la chaîne trophique, sont sensibles aux modifications de leur milieu (pollution, bruit sous-marin, changement climatique) et leur état permet d’évaluer l’état global de l’écosystème marin. Leur suivi est donc une forme de “sentinelle” pour la biodiversité marine.', ARRAY['Mammifères marins','Biodiversité marine','Indicateurs écologiques','Pollution'], ARRAY[])
